import{c as t,Q as a,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I create a service account / API credential?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/create-service-account.md","filePath":"guide/recipes/portal/create-service-account.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/portal/create-service-account.md"};function c(i,e,n,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-create-a-service-account-api-credential" tabindex="-1">How do I create a service account / API credential? <a class="header-anchor" href="#how-do-i-create-a-service-account-api-credential" aria-label="Permalink to &quot;How do I create a service account / API credential?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Service accounts are non-human identities used by your scripts, CI jobs, or back-office tools to call Console APIs. Each has a client ID + secret pair and a scoped set of grants.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings → Service Accounts</strong>.</li><li>Click <strong>New Service Account</strong>.</li><li>Fill in: <ul><li><strong>Name</strong> — e.g. <code>ci-deploy-bot</code>.</li><li><strong>Description</strong> — what this account does (helps future-you).</li><li><strong>Grants</strong> — pick the API surfaces it needs. Default is read-only.</li></ul></li><li>Click <strong>Create</strong>.</li><li>The credentials modal appears with the <strong>Client ID</strong> and <strong>Client Secret</strong>. <strong>Copy them now</strong> — the secret is shown only once.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The service account appears in the table with status <strong>Active</strong>. Your scripts use the client ID and secret to obtain an access token via OAuth2 client-credentials flow, then call the Console API as that account.</p><div class="tip custom-block"><p class="custom-block-title">Lost the secret</p><p>Use <strong>Rotate Secret</strong> on the row&#39;s actions menu. The old secret is revoked immediately and a fresh one is shown — copy it before closing the modal.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./register-webhook">How do I register a webhook?</a></li></ul>',10)])])}const g=t(r,[["render",c]]);export{p as __pageData,g as default};
